#include <stdio.h>
#include <string.h>

#define MAX_ENTRIES 1024
#define MAC_ADDR_LEN 6

typedef struct {
    unsigned char mac[MAC_ADDR_LEN];
    int port;
    int timestamp;
    int valid;
} MacEntry;

MacEntry mac_table[MAX_ENTRIES];

// Initialize MAC table
void init_mac_table() {
    memset(mac_table, 0, sizeof(mac_table));
}

// Learn MAC address from incoming frame
void learn_mac(unsigned char* src_mac, int port, int current_time) {
    // Search for existing entry
    for (int i = 0; i < MAX_ENTRIES; i++) {
        if (mac_table[i].valid && 
            memcmp(mac_table[i].mac, src_mac, MAC_ADDR_LEN) == 0) {
            mac_table[i].port = port;  // Update port
            mac_table[i].timestamp = current_time;
            return;
        }
    }

    // Add new entry
    for (int i = 0; i < MAX_ENTRIES; i++) {
        if (!mac_table[i].valid) {
            memcpy(mac_table[i].mac, src_mac, MAC_ADDR_LEN);
            mac_table[i].port = port;
            mac_table[i].timestamp = current_time;
            mac_table[i].valid = 1;
            return;
        }
    }
}

// Lookup destination port for MAC
int lookup_port(unsigned char* dest_mac) {
    for (int i = 0; i < MAX_ENTRIES; i++) {
        if (mac_table[i].valid &&
            memcmp(mac_table[i].mac, dest_mac, MAC_ADDR_LEN) == 0) {
            return mac_table[i].port;
        }
    }
    return -1;  // Unknown - flood
}

// Switch forwarding decision
void forward_frame(unsigned char* dest_mac, unsigned char* src_mac, 
                   int in_port, int current_time) {
    // Learn source MAC
    learn_mac(src_mac, in_port, current_time);

    // Find destination port
    int out_port = lookup_port(dest_mac);

    if (out_port == -1) {
        // Flood to all ports except source
        flood_except(in_port);
    } else {
        // Forward to specific port
        send_to_port(out_port, dest_mac);
    }
}
